// Attempt at generating an invoice from purchase order
fn generate_invoice(po: &PurchaseOrder) -> Invoice {
  let mut items = vec![];
  for item in &po.items {
    items.push(InvoiceItem {
      description: item.description.clone(),
      quantity: item.quantity,
      price_per_unit: item.price_per_unit,
    });
  }
  Invoice { order_id: po.order_id.clone(), total_amount: calculate_total(&items), items }
}

// Calculate total amount
fn calculate_total(items: &[InvoiceItem]) -> f64 {
  let mut sum = 0.0;
  for item in items.iter() {
    sum += item.price_per_unit * item.quantity as f64;
  }
  sum
}

// Sample structs
data PurchaseOrder { order_id: String, items: Vec<Item> }
data Item { description: String, quantity: u32, price_per_unit: f64 }
data InvoiceItem { description: String, quantity: u32, price_per_unit: f64 }
data Invoice { order_id: String, total_amount: f64, items: Vec<InvoiceItem> }

// Test function
test fn test_generate_invoice() {
  let po = PurchaseOrder {
    order_id: "ORD001".to_string(),
    items: vec![
      Item {
        description: "Laptop"
        quantity: 2,
        price_per_unit: 999.50
      }
    ],
  };
  let invoice = generate_invoice(&po);
  assert_eq!(invoice.order_id, po.order_id);
  assert_eq!(invoice.total_amount, calculate_total(&invoice.items));
}

